(() => {
  const defaultFont = '500 15px Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif';
  const monoFont = '12px "SFMono-Regular", ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace';
  let ctx = null;

  const ensureContext = () => {
    if (ctx) {
      return ctx;
    }
    const canvas = document.createElement('canvas');
    ctx = canvas.getContext('2d');
    return ctx;
  };

  const measureText = (value, options = {}) => {
    const context = ensureContext();
    const font = typeof options === 'string' ? options : options.font || defaultFont;
    const text = String(value || '');
    if (!context) {
      return { width: text.length * 8, height: 14 };
    }
    context.font = font;
    const metrics = context.measureText(text);
    const height = Math.ceil((metrics.actualBoundingBoxAscent || 8) + (metrics.actualBoundingBoxDescent || 4));
    return { width: metrics.width || 0, height: height || 14 };
  };

  const layoutBlock = (value, options = {}) => {
    const text = String(value || '');
    const font = options.font || defaultFont;
    const lineHeight = options.lineHeight || 22;
    const maxWidth = options.maxWidth && options.maxWidth > 0 ? options.maxWidth : Number.POSITIVE_INFINITY;
    const lines = [];
    const widthOf = (line) => measureText(line, { font }).width;

    const pushWrappedLine = (rawLine) => {
      const normalized = String(rawLine || '').replace(/\t/g, '  ');
      if (!normalized) {
        lines.push('');
        return;
      }

      const parts = normalized.split(/(\s+)/).filter((part) => part.length > 0);
      let current = '';
      parts.forEach((part) => {
        const candidate = current + part;
        if (current && widthOf(candidate) > maxWidth) {
          lines.push(current.trimEnd());
          current = part.trimStart();
          return;
        }
        current = candidate;
      });
      lines.push(current || '');
    };

    text.split(/\r?\n/).forEach(pushWrappedLine);
    const width = Math.max(0, ...lines.map((line) => widthOf(line)));
    return {
      lines,
      width,
      height: Math.max(lineHeight, lines.length * lineHeight),
      lineHeight,
      font,
      maxWidth,
    };
  };

  const highlight = (root) => {
    (root || document).querySelectorAll('pre code').forEach((node) => {
      if (node.parentElement) {
        node.parentElement.dataset.pretext = 'ready';
      }
      node.dataset.pretext = 'ready';
      if (!node.getAttribute('data-language')) {
        node.setAttribute('data-language', 'text');
      }
    });
  };

  window.Pretext = {
    defaultFont,
    monoFont,
    highlight,
    measureText,
    layoutBlock,
  };
})();
